        'privacy__sharing_info_title' => 'Compartir información y comunicaciones no deseadas',
        'privacy__sharing_info_text' => 'Excepto para procesadores de pago y socios locales autorizados, no compartimos tus datos personales con terceros. Enviamos solo comunicaciones que hayas solicitado expresamente (newsletter solo si te suscribiste en el sitio).',
        'privacy__security_title' => 'Cómo protegemos los datos recopilados',
